(() => {
  'use strict';
  const $ = id => document.getElementById(id);
  const gate=$('authGate'), app=$('appointmentApp'), loginBtn=$('loginBtn'), logoutBtn=$('logoutBtn'), userEmail=$('userEmail');
  const list=$('appointmentList'), search=$('appointmentSearch'), statusFilter=$('statusFilter'), dateFilter=$('dateFilter'), serviceFilter=$('serviceFilter'), exportCsv=$('exportCsv');
  let user=null, appointments=[];
  const STATUS={new:['Yeni','status-new'],callback:['Aranacak','status-callback'],contacted:['Görüşüldü','status-contacted'],confirmed:['Onaylandı','status-confirmed'],arrived:['Kliniğe geldi','status-arrived'],completed:['Tamamlandı','status-completed'],cancelled:['İptal','status-cancelled'],archived:['Arşiv','status-archived']};
  const norm=value=>String(value||'').toLocaleLowerCase('tr-TR');
  const esc=value=>String(value??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
  const formatDate=value=>{if(!value)return'—';const date=new Date(value.includes('T')?value:`${value}T12:00:00`);return Number.isNaN(date.getTime())?value:date.toLocaleDateString('tr-TR',{day:'2-digit',month:'long',year:'numeric'})};
  async function headers(){try{const token=await user?.jwt?.();return token?{Authorization:`Bearer ${token}`,'Content-Type':'application/json'}:{'Content-Type':'application/json'}}catch{return{'Content-Type':'application/json'}}}
  async function api(method='GET',body){const response=await fetch('/.netlify/functions/appointments',{method,headers:await headers(),credentials:'same-origin',cache:'no-store',body:body?JSON.stringify(body):undefined});let data={};try{data=await response.json()}catch{}if(!response.ok)throw new Error(data.error||'İşlem tamamlanamadı');return data}
  function showApp(current){user=current;userEmail.textContent=current?.email||'';gate.classList.add('hidden');app.classList.remove('hidden');load()}
  function showLogin(){user=null;app.classList.add('hidden');gate.classList.remove('hidden')}
  async function load(){try{const data=await api();appointments=Array.isArray(data.appointments)?data.appointments:[];buildServiceFilter();render()}catch(error){console.error(error);list.innerHTML='<div class="empty">Randevular yüklenemedi. Yetki ve Netlify ayarlarını kontrol edin.</div>'}}
  function buildServiceFilter(){const current=serviceFilter.value;const services=[...new Set(appointments.map(item=>item.service).filter(Boolean))].sort((a,b)=>a.localeCompare(b,'tr'));serviceFilter.innerHTML='<option value="">Tüm hizmetler</option>'+services.map(value=>`<option value="${esc(value)}">${esc(value)}</option>`).join('');serviceFilter.value=current}
  function filtered(){const query=norm(search.value).trim();return appointments.filter(item=>{if(statusFilter.value&&item.status!==statusFilter.value)return false;if(dateFilter.value&&item.requestedDate!==dateFilter.value)return false;if(serviceFilter.value&&item.service!==serviceFilter.value)return false;if(!query)return true;return norm([item.ownerName,item.phone,item.email,item.petName,item.species,item.age,item.breed,item.service,item.requestedDate,item.requestedTime,item.note].join(' ')).includes(query)})}
  function downloadCsv(){
    const rows=filtered();
    if(!rows.length){alert('Dışa aktarılacak randevu bulunamadı.');return}
    const columns=[['createdAt','Talep zamanı'],['status','Durum'],['ownerName','Hasta sahibi'],['phone','Telefon'],['email','E-posta'],['petName','Hayvan adı'],['species','Tür'],['age','Yaş'],['breed','Irk/Cins'],['service','Hizmet'],['requestedDate','Talep edilen tarih'],['requestedTime','Talep edilen saat'],['internalNote','Klinik içi not']];
    const quote=value=>`"${String(value??'').replace(/"/g,'""')}"`;
    const csv='\ufeff'+[columns.map(([,label])=>quote(label)).join(';'),...rows.map(item=>columns.map(([key])=>quote(item[key])).join(';'))].join('\r\n');
    const url=URL.createObjectURL(new Blob([csv],{type:'text/csv;charset=utf-8'}));
    const link=document.createElement('a');link.href=url;link.download=`elci-randevular-${new Date().toISOString().slice(0,10)}.csv`;document.body.appendChild(link);link.click();link.remove();URL.revokeObjectURL(url);
  }
  function updateCounts(){const today=new Date().toISOString().slice(0,10);$('countNew').textContent=appointments.filter(x=>x.status==='new').length;$('countCallback').textContent=appointments.filter(x=>x.status==='callback').length;$('countConfirmed').textContent=appointments.filter(x=>x.status==='confirmed').length;$('countToday').textContent=appointments.filter(x=>x.requestedDate===today).length;$('countTotal').textContent=appointments.length}
  function options(current){return Object.entries(STATUS).map(([value,[label]])=>`<option value="${value}"${current===value?' selected':''}>${label}</option>`).join('')}
  function history(item){const rows=(item.history||[]).slice().reverse().map(row=>`<li><strong>${formatDate(row.at)}</strong> · ${esc(row.type||'işlem')} · ${esc(row.detail||'')}</li>`).join('');return rows?`<details class="history"><summary>İşlem geçmişini göster</summary><ul>${rows}</ul></details>`:''}
  function card(item){const [label,cls]=STATUS[item.status]||STATUS.new;return `<article class="appointment-card ${item.status==='new'?'is-new':''}" data-id="${esc(item.id)}">
    <div class="appointment-summary"><div><h3>${esc(item.petName||'İsimsiz')} — ${esc(item.ownerName||'Hasta sahibi')}</h3><p>${esc(item.species||'Tür belirtilmedi')} · ${esc(item.service||'Hizmet belirtilmedi')}</p></div><div><span class="appointment-label">Talep edilen tarih</span><span class="appointment-value">${esc(formatDate(item.requestedDate))}</span></div><div><span class="appointment-label">Saat</span><span class="appointment-value">${esc(item.requestedTime||'—')}</span></div><div><span class="status ${cls}">${label}</span><br><button type="button" class="toggle-details">Detayları aç</button></div></div>
    <div class="appointment-details"><div class="details-grid"><div class="detail-box"><span class="appointment-label">Telefon</span><a class="appointment-value" href="tel:${esc(item.phone||'')}">${esc(item.phone||'—')}</a></div><div class="detail-box"><span class="appointment-label">E-posta</span><span class="appointment-value">${esc(item.email||'—')}</span></div><div class="detail-box"><span class="appointment-label">Hayvan</span><span class="appointment-value">${esc([item.species,item.age,item.breed].filter(Boolean).join(' · ')||'—')}</span></div><div class="detail-box"><span class="appointment-label">Talep oluşturma</span><span class="appointment-value">${esc(formatDate(item.createdAt))}</span></div>${item.note?`<div class="detail-box wide"><span class="appointment-label">Hasta sahibi notu</span><span class="appointment-value">${esc(item.note)}</span></div>`:''}</div>
    <div class="note-wrap"><label class="appointment-label" for="note-${esc(item.id)}">Klinik içi not</label><textarea id="note-${esc(item.id)}" rows="3">${esc(item.internalNote||'')}</textarea></div>
    <div class="appointment-actions"><a class="admin-btn primary" href="tel:${esc(item.phone||'')}"><i class="fa-solid fa-phone"></i> Ara</a><select class="status-select" aria-label="Randevu durumu">${options(item.status)}</select><button type="button" class="admin-btn save-note">Notu kaydet</button><button type="button" class="admin-btn delete-btn"><i class="fa-regular fa-trash-can"></i> Kalıcı sil</button></div>${history(item)}</div></article>`}
  function bind(){list.querySelectorAll('.appointment-card').forEach(cardEl=>{const id=cardEl.dataset.id;cardEl.querySelector('.toggle-details')?.addEventListener('click',event=>{cardEl.classList.toggle('open');event.currentTarget.textContent=cardEl.classList.contains('open')?'Detayları kapat':'Detayları aç'});cardEl.querySelector('.status-select')?.addEventListener('change',event=>update(id,{status:event.target.value}));cardEl.querySelector('.save-note')?.addEventListener('click',()=>update(id,{internalNote:cardEl.querySelector('textarea').value}));cardEl.querySelector('.delete-btn')?.addEventListener('click',()=>remove(id))})}
  function render(){updateCounts();const items=filtered();list.innerHTML=items.length?items.map(card).join(''):'<div class="empty">Bu filtrelerle eşleşen randevu bulunamadı.</div>';bind()}
  async function update(id,changes){try{const data=await api('PATCH',{id,...changes});const index=appointments.findIndex(item=>item.id===id);if(index>=0)appointments[index]=data.appointment;render()}catch(error){alert(error.message)}}
  async function remove(id){if(!confirm('Bu randevu kaydı kalıcı olarak silinecek. Bu işlem geri alınamaz. Devam edilsin mi?'))return;try{await api('DELETE',{id});appointments=appointments.filter(item=>item.id!==id);render()}catch(error){alert(error.message)}}
  [search,statusFilter,dateFilter,serviceFilter].forEach(element=>element?.addEventListener('input',render));exportCsv?.addEventListener('click',downloadCsv);loginBtn?.addEventListener('click',()=>window.netlifyIdentity?.open('login'));logoutBtn?.addEventListener('click',()=>window.netlifyIdentity?.logout());
  if(window.netlifyIdentity){window.netlifyIdentity.on('init',current=>current?showApp(current):showLogin());window.netlifyIdentity.on('login',current=>{showApp(current);window.netlifyIdentity.close()});window.netlifyIdentity.on('logout',showLogin);window.netlifyIdentity.init()}else showLogin();
})();
